import{_ as t,Z as a,P as p,g as l,k as r,m as e}from"./chunks/framework.Dp5g00Bf.js";const m=JSON.parse('{"title":"解决低内存服务器崩溃问题","description":"","frontmatter":{},"headers":[],"relativePath":"views/1-开发🌏/3-运维/解决低内存服务器崩溃问题/index.md","filePath":"views/1-开发🌏/3-运维/解决低内存服务器崩溃问题/index.md","lastUpdated":1778336291000}'),d={name:"views/1-开发🌏/3-运维/解决低内存服务器崩溃问题/index.md"};function h(o,s,c,b,k,u){const i=a("NolebaseGitContributors"),n=a("NolebaseGitChangelog");return p(),l("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778336291000"},[s[0]||(s[0]=r(`<h1 id="解决低内存服务器崩溃问题" tabindex="-1">解决低内存服务器崩溃问题 <a class="header-anchor" href="#解决低内存服务器崩溃问题" aria-label="Permalink to &quot;解决低内存服务器崩溃问题&quot;">​</a></h1><p>如果你和我一样，为了最高性价比买了低内存的服务器，一定遇到过莫名其妙cpu、内存各种占用飙升导致服务器崩溃的情况。如果不是被黑客攻击了，那很有可能是ubuntu系统的自动更新在作祟。所以我们两个步骤可以优化.</p><h2 id="一、关闭系统更新" tabindex="-1">一、关闭系统更新 <a class="header-anchor" href="#一、关闭系统更新" aria-label="Permalink to &quot;一、关闭系统更新&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dpkg-reconfigure</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -plow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unattended-upgrades</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>选择no</p></blockquote><h2 id="二、开启swap" tabindex="-1">二、开启swap <a class="header-anchor" href="#二、开启swap" aria-label="Permalink to &quot;二、开启swap&quot;">​</a></h2><p>在 Ubuntu 上开启或重新配置 Swap 的标准步骤如下：</p><h3 id="_1-检查当前-swap-状态" tabindex="-1">1. 检查当前 Swap 状态 <a class="header-anchor" href="#_1-检查当前-swap-状态" aria-label="Permalink to &quot;1. 检查当前 Swap 状态&quot;">​</a></h3><p>在操作之前，先看系统是否已经挂载了 Swap：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swapon</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --show</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或者</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果输出为空，说明目前没有激活的 Swap。</p><hr><h3 id="_2-创建-swap-文件" tabindex="-1">2. 创建 Swap 文件 <a class="header-anchor" href="#_2-创建-swap-文件" aria-label="Permalink to &quot;2. 创建 Swap 文件&quot;">​</a></h3><p>如果你需要创建一个 <strong>2GB</strong> 的 Swap 文件（大小可以根据需求调整，如 <code>4G</code>）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建一个指定大小的文件 (推荐使用 fallocate，速度快)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fallocate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 2G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 如果 fallocate 报错，可以使用 dd 命令代替：</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># sudo dd if=/dev/zero of=/swapfile bs=1M count=2048</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="_3-设置文件权限" tabindex="-1">3. 设置文件权限 <a class="header-anchor" href="#_3-设置文件权限" aria-label="Permalink to &quot;3. 设置文件权限&quot;">​</a></h3><p><strong>极其重要</strong>：为了安全，Swap 文件必须只能由 root 用户读写。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-将文件格式化为-swap-格式" tabindex="-1">4. 将文件格式化为 Swap 格式 <a class="header-anchor" href="#_4-将文件格式化为-swap-格式" aria-label="Permalink to &quot;4. 将文件格式化为 Swap 格式&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkswap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_5-启用-swap-文件" tabindex="-1">5. 启用 Swap 文件 <a class="header-anchor" href="#_5-启用-swap-文件" aria-label="Permalink to &quot;5. 启用 Swap 文件&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swapon</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /swapfile</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>此时再次运行 <code>free -h</code>，你应该能看到 Swap 空间已经增加了。</p><hr><h3 id="_6-设置永久生效-写入-fstab" tabindex="-1">6. 设置永久生效 (写入 fstab) <a class="header-anchor" href="#_6-设置永久生效-写入-fstab" aria-label="Permalink to &quot;6. 设置永久生效 (写入 fstab)&quot;">​</a></h3><p>为了让服务器重启后自动开启 Swap，需要修改 <code>/etc/fstab</code> 文件。</p><p><strong>注意：</strong> 结合你之前的报错 <code>Duplicate entry in /etc/fstab?</code>，请务必先检查该文件：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/fstab</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li>检查文件末尾是否已经有了关于 <code>/swapfile</code> 的行。</li><li>如果有重复的，删掉多余的。</li><li>确保只有一行如下内容：<div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/swapfile none swap sw 0 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>保存退出（Ctrl+O, Enter, Ctrl+X）。</li></ol><hr><h3 id="_7-优化-swap-使用倾向-swappiness" tabindex="-1">7. 优化 Swap 使用倾向 (Swappiness) <a class="header-anchor" href="#_7-优化-swap-使用倾向-swappiness" aria-label="Permalink to &quot;7. 优化 Swap 使用倾向 (Swappiness)&quot;">​</a></h3><p><code>swappiness</code> 参数控制系统多快开始使用 Swap（取值 0-100）。对于云服务器，建议设为 <strong>10</strong> 或 <strong>20</strong>，防止过度频繁读写硬盘导致 IO 飙升。</p><ul><li><strong>查看当前值</strong>：<code>cat /proc/sys/net/ipv4/tcp_keepalive_time</code> (默认通常是 60)</li><li><strong>临时修改</strong>：<code>sudo sysctl vm.swappiness=10</code></li><li><strong>永久修改</strong>： 编辑 <code>/etc/sysctl.conf</code>，在末尾添加：<div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vm.swappiness=10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul>`,33)),e(i),e(n)])}const v=t(d,[["render",h]]);export{m as __pageData,v as default};
